/// Constructor dependencies are resolved from the DI container automatically.
/// </summary>
[McpServerToolType]
public sealed class WeatherTools
{
    private readonly HttpClient _http;

    public WeatherTools(HttpClient httpClient)
    {
        _http = httpClient;
    }

    [McpServerTool(Name = "get_weather")]
    [Description("Get the current weather for a city.")]
    public async Task<string> GetWeatherAsync(
        [Description("City name, e.g. 'Seattle'")] string city,
        CancellationToken cancellationToken = default)
    {
        var response = await _http.GetFromJsonAsync<WeatherResponse>(
            $"/weather?city={Uri.EscapeDataString(city)}",
            cancellationToken);

        if (response is null)
            return $"No weather data found for {city}.";

        return $"{city}: {response.Temperature}°C, {response.Condition}";
    }

    [McpServerTool(Name = "get_forecast")]
    [Description("Get a multi-day weather forecast for a city.")]
    public async Task<string> GetForecastAsync(
        [Description("City name")] string city,
        [Description("Number of days (1-7)")] int days = 3,
        CancellationToken cancellationToken = default)
    {
        var response = await _http.GetFromJsonAsync<ForecastResponse>(
            $"/forecast?city={Uri.EscapeDataString(city)}&days={days}",
            cancellationToken);

        if (response?.Days is null or { Count: 0 })
            return $"No forecast data found for {city}.";

        var lines = response.Days.Select(d => $"  {d.Date}: {d.Temperature}°C, {d.Condition}");
        return $"Forecast for {city}:\n{string.Join('\n', lines)}";
    }
}

